 64→void ULFPDeploymentWidget::MarkUnitPlaced(int32 PartyIndex, bool bPlaced)
 65→{
 66→	if (!PlacedStates.IsValidIndex(PartyIndex)) return;
 67→
 68→	PlacedStates[PartyIndex] = bPlaced;
 69→	UpdateSlotVisual(PartyIndex);
 70→
 71→	// 检查是否全部放置完毕
 72→	bool bAllPlaced = true;
 73→	for (int32 i = 0; i < CachedPartyUnits.Num() && i < PlacedStates.Num(); i++)
 74→	{
 75→		if (CachedPartyUnits[i].IsValid() && !PlacedStates[i])
 76→		{
 77→			bAllPlaced = false;
 78→			break;
 79→		}
 80→	}
 81→	SetConfirmEnabled(bAllPlaced);
 82→}
